/*
  Data Step: Process raw sales transaction data to calculate profit margins
  and flag high-value transactions for the regional report.
*/

DATA work.sales_summary;
    /* Define length for character variables to avoid truncation */
    LENGTH Region $ 20 Product_Category $ 30 SalesRep $ 25;

    /* Set format for currency and percentage variables */
    FORMAT Revenue Cost Profit_Margin DOLLAR12.2;
    FORMAT Profit_Margin PERCENT8.1;

    /* Read from the raw transaction dataset */
    SET raw_data.transactions (KEEP=Transaction_ID Region Product_Category Revenue Cost SalesRep);

    /* Calculate derived numeric variables */
    Profit = Revenue - Cost;

    /* Calculate profit margin, handling potential division by zero */
    if Revenue > 0 then Profit_Margin = Profit / Revenue;
    else Profit_Margin = 0;

    /* Determine transaction status based on revenue threshold */
    if Revenue >= 50000 then Status = 'High Value';
    else if Revenue >= 10000 then Status = 'Standard';
    else Status = 'Low Volume';

    /* Logic to flag specific product categories for review */
    if Product_Category = 'Electronics' and Profit_Margin < 0.10 then Flag_Review = 'Y';
    else Flag_Review = 'N';

    /* Drop intermediate calculation variable 'Profit' from final output */
    DROP Profit;

    /* Keep only necessary variables for the summary report */
    KEEP Transaction_ID Region Product_Category SalesRep Revenue Cost Profit_Margin Status Flag_Review;

RUN;

/* Summary log message (optional for debugging) */
PROC PRINT DATA=work.sales_summary (OBS=5);
    TITLE 'Preview of Processed Sales Summary';
RUN;

/*
 * Data Step: Patient Risk Stratification and Data Cleaning
 * This step processes raw clinical trial data to calculate a risk score,
 * assign risk categories, and clean up unnecessary variables.
 */

data work.patient_risk_assessment;
    /* Define lengths for new character variables to avoid truncation */
    length risk_category $ 20 treatment_arm $ 15;

    /* Set format for calculated numeric variable */
    format risk_score 8.2;

    /* Read from the raw clinical dataset */
    set clinical.raw_patients (keep=patient_id age systolic_bp diastolic_bp bmi treatment_arm enrollment_date);

    /* Initialize risk score to missing */
    risk_score = .;

    /* Calculate risk score based on clinical indicators */
    if bmi >= 30 and systolic_bp > 140 then do;
        risk_score = 100;
    end;
    else if bmi >= 25 and systolic_bp > 130 then do;
        risk_score = 75;
    end;
    else if bmi < 25 and systolic_bp <= 120 then do;
        risk_score = 25;
    end;
    else do;
        /* Linear interpolation for intermediate values */
        risk_score = (bmi * 2) + (systolic_bp - 100);
    end;

    /* Assign risk category based on calculated score */
    if risk_score >= 80 then risk_category = 'High Risk';
    else if risk_score >= 50 then risk_category = 'Moderate Risk';
    else risk_category = 'Low Risk';

    /* Handle missing data logic */
    if missing(systolic_bp) or missing(diastolic_bp) then delete;

    /* Drop variables not needed for the final output dataset */
    drop bmi enrollment_date;

    /* Add a flag for data quality check */
    if risk_score > 100 then risk_score = 100;

run;

/* Verify the output structure */
proc print data=work.patient_risk_assessment (obs=10);
    title 'First 10 Records of Patient Risk Assessment';
run;

/* 
   Purpose: Process raw clinical trial enrollment data to create a cleaned analysis dataset.
   This step handles complex logic for eligibility flags, calculates derived metrics,
   and standardizes date formats for downstream reporting.
*/

/* Define lengths for character variables to avoid truncation during concatenation */
length 
    SubjectID $ 12 
    SiteName $ 50 
    EnrollmentStatus $ 20 
    RiskCategory $ 15 
    Comments $ 200;

/* Set formats for numeric and date variables */
format 
    Age 3. 
    BaselineBP 5.1 
    EnrollmentDate mmddyy10. 
    LastVisitDate mmddyy10. 
    DaysOnStudy 5.0;

data work.clinical_analysis;
    set raw.clinical_enrollment (keep=subject_id site_code age gender baseline_bp enrollment_dt last_visit_dt 
                                 adverse_event_flag consent_status); 

    /* Rename variables for clarity in the output dataset */
    rename 
        subject_id = SubjectID 
        site_code = SiteCode 
        enrollment_dt = EnrollmentDate 
        last_visit_dt = LastVisitDate 
        adverse_event_flag = AdverseEventFlag 
        consent_status = ConsentStatus;

    /* Convert character site codes to descriptive names using a lookup logic */
    if SiteCode = 'US-01' then SiteName = 'New York General';
    else if SiteCode = 'US-02' then SiteName = 'Boston Research Center';
    else if SiteCode = 'EU-05' then SiteName = 'London Clinical Unit';
    else SiteName = 'Unknown Site';

    /* Calculate days on study with validation checks */
    if not missing(EnrollmentDate) and not missing(LastVisitDate) then do;
        DaysOnStudy = LastVisitDate - EnrollmentDate;
        if DaysOnStudy < 0 then DaysOnStudy = 0; /* Data cleaning: handle negative durations */
    end;
    else DaysOnStudy = .;

    /* Complex logic for Risk Category assignment based on multiple conditions */
    if Age < 18 then do;
        RiskCategory = 'Pediatric';
    end;
    else if Age >= 65 and BaselineBP > 140 then do;
        RiskCategory = 'High Risk - Elderly';
    end;
    else if BaselineBP > 130 and BaselineBP <= 140 then do;
        RiskCategory = 'Moderate Risk';
    end;
    else do;
        RiskCategory = 'Low Risk';
    end;

    /* Determine Enrollment Status based on consent and adverse events */
    if ConsentStatus = 'Signed' and AdverseEventFlag = 'N' then do;
        EnrollmentStatus = 'Active Participant';
    end;
    else if ConsentStatus = 'Signed' and AdverseEventFlag = 'Y' then do;
        EnrollmentStatus = 'Adverse Event Reported';
    end;
    else if ConsentStatus = 'Not Signed' then do;
        EnrollmentStatus = 'Pending Consent';
    end;
    else do;
        EnrollmentStatus = 'Unknown Status';
    end;

    /* Generate a composite comment field for audit trail */
    if RiskCategory = 'High Risk - Elderly' then Comments = 'Elderly subject with elevated BP flagged for review';
    else if EnrollmentStatus = 'Adverse Event Reported' then Comments = 'Safety review required immediately';
    else Comments = 'Standard enrollment protocol followed';

    /* Drop raw variables that are no longer needed in the analysis dataset */
    drop SiteCode AdverseEventFlag ConsentStatus;

    /* Final validation: Ensure all required fields are populated */
    if missing(SubjectID) or missing(RiskCategory) then output; 
    else output;
run;

/* Log confirmation */
proc print data=work.clinical_analysis (obs=5);
    title 'Preview of Processed Clinical Analysis Dataset';
run;

/* 
   Purpose: Merge Customer Master data with recent Transaction data.
   Demonstrates MERGE_SEMANTICS including:
   1. One-to-One merge (Customer ID to Demographics)
   2. One-to-Many merge (Customer ID to Transactions)
   3. UPDATE statement usage to overwrite existing values with new data.
*/

/* Step 1: Sort datasets by the BY variable (CustomerID) */
proc sort data=work.customer_master out=sorted_master;
    by CustomerID;
run;

proc sort data=work.transactions out=sorted_trans;
    by CustomerID;
run;

/* Step 2: Perform the MERGE with UPDATE semantics */
data work.customer_enriched;
    /* 
       MERGE_SEMANTICS PATTERN:
       - The UPDATE statement is used instead of a standard SET to handle 
         updates from the second dataset.
       - One-to-One: If a CustomerID exists in both, the 'transactions' 
         values (e.g., LastTransactionDate) update the master record.
       - One-to-Many: Since 'transactions' has multiple records per ID, 
         the UPDATE statement will process the last occurrence for the 
         variable being updated, effectively overwriting previous values 
         from the master or earlier transaction records for that ID.
    */
    merge 
        work.sorted_master (in=has_master)
        work.sorted_trans (in=has_trans)
    ;
    by CustomerID;

    /* Logic to handle the merge result */
    if has_master then do;
        /* Initialize flags if this is the first time seeing the ID in the merge */
        if first.CustomerID then do;
            /* Keep original master data unless overwritten by update */
            /* Variables from 'transactions' will update these if present */
        end;

        /* If a transaction record exists, the UPDATE statement (implicit in the merge logic 
           when using the UPDATE option or specific data step logic) handles the overwrite. 
           Here we simulate the specific UPDATE behavior often seen in complex merges: */
        if has_trans then do;
            /* In a true UPDATE statement context: 
               update(sorted_master) sorted_trans; 
               But in a standard MERGE, we manually handle the 'last' observation logic 
               to mimic the update behavior for specific variables. */
            LastTransactionDate = LastTransDate; 
            TransactionCount = Count;
        end;
    end;
    else if has_trans then do;
        /* Handle cases where a transaction exists but no master record (New Customer) */
        /* This would typically be handled by a separate logic or pre-existing master */
        output;
    end;
    else do;
        /* Master exists but no new transactions; keep original */
        output;
    end;
run;

/* Step 3: Verify the merge result */
proc print data=work.customer_enriched (obs=10);
    title "Merged Customer Data with Updated Transaction Info";
run;

/*
 * SAS Code: Customer Transaction Aggregation and Update
 * Category: DATA_STEP_MERGE
 * Complexity: MODERATE
 * Description: Merges customer demographic data with transaction history.
 *              Demonstrates one-to-one merge (Customer ID to Demographics)
 *              and one-to-many merge (Customer ID to Transactions).
 *              Uses MERGE_SEMANTICS to update the master dataset with
 *              new or modified transaction records from the update dataset.
 */

/* Step 1: Sort datasets by the BY variable (Customer_ID) */
proc sort data=work.customer_demographics out=sorted_demog;
    by Customer_ID;
run;

proc sort data=work.transaction_history out=sorted_trans;
    by Customer_ID Transaction_Date;
run;

/* Step 2: Merge datasets using MERGE_SEMANTICS pattern */
/* 
 * Logic: 
 * - 'sorted_demog' acts as the base (master) dataset.
 * - 'sorted_trans' acts as the update dataset.
 * - The IN== dataset options track which dataset contributes to the observation.
 * - 'Last.Transaction_Date' logic ensures we keep the most recent transaction 
 *   if multiple exist for a customer in the update set (one-to-many handling).
 */
data work.customer_combined_final (keep=Customer_ID First_Name Last_Name Total_Spend Last_Transaction_Date);
    merge sorted_demog (in=in_demog)
          sorted_trans (in=in_trans);
    by Customer_ID;

    /* 
     * MERGE_SEMANTICS Implementation:
     * We are updating the base record with transaction aggregates.
     * If a customer exists in both, we calculate totals.
     * If only in demographics, we keep demographics with nulls for trans.
     */
    if in_demog then do;
        /* Initialize or retain accumulators for the one-to-many loop */
        retain Total_Spend 0 Last_Transaction_Date '';

        /* Reset accumulators at the start of a new Customer_ID group */
        if first.Customer_ID then do;
            Total_Spend = 0;
            Last_Transaction_Date = '';
        end;

        /* Accumulate transaction data if present (One-to-Many logic) */
        if in_trans then do;
            Total_Spend + Transaction_Amount;
            /* Update last transaction date if current is newer */
            if Transaction_Date > Last_Transaction_Date then
                Last_Transaction_Date = Transaction_Date;
        end;

        /* 
         * Output logic: 
         * In a standard MERGE_SEMANTICS update scenario, we might output 
         * only if the update dataset contributed, or output the master 
         * with updated values. Here we output the enriched record.
         */
        output;
    end;
    else if in_trans then do;
        /* 
         * Optional: Handle 'orphan' transactions that don't match demographics.
         * In strict MERGE_SEMANTICS for updates, these might be ignored 
         * or written to a separate error log. Here we skip them to match 
         * the requirement of updating the master demographic list.
         */
        /* Do nothing - only output records with valid demographics */
    end;
run;

/* Step 3: Verify the merge result */
proc print data=work.customer_combined_final (obs=10);
    title "First 10 Records of Merged Customer Data";
run;

/* 
 * Complex Data Merge: Patient Demographics + Clinical Encounters + Billing Updates
 * Category: DATA_STEP_MERGE
 * Complexity: HIGH
 * Pattern: MERGE_SEMANTICS (One-to-One, One-to-Many, and UPDATE logic combined)
 */

/* 
 * Step 1: Ensure datasets are sorted by the merge key (Patient_ID)
 * This is a strict requirement for the MERGE statement to function correctly.
 */
proc sort data=clinical.patients_demographics out=work.patients_sorted;
    by Patient_ID;
run;

proc sort data=clinical.encounters out=work.encounters_sorted;
    by Patient_ID Visit_Date;
run;

proc sort data=billing.billing_updates out=work.updates_sorted;
    by Patient_ID Claim_Date;
run;

/* 
 * Step 2: The Complex MERGE Operation
 * This DATA step demonstrates MERGE_SEMANTICS by combining:
 * 1. One-to-One: Merging basic demographics with the latest status.
 * 2. One-to-Many: Merging patient records with multiple encounter history.
 * 3. UPDATE Logic: Using the UPDATE statement logic implicitly via conditional processing
 *    to overwrite specific fields from the 'updates' dataset where matches occur.
 * 
 * We utilize the IN= dataset options to control logic flow for non-matching records.
 */
data work.patient_master_combined;
    length Status_Flag $ 10;
    retain First_Visit_Date; /* Retain variable for logic across iterations */

    /* 
     * MERGE Statement with IN= variables to track source presence.
     * 'p' = Patients (Master)
     * 'e' = Encounters (Detail - One-to-Many)
     * 'u' = Billing Updates (Transaction - Used for conditional overwrites)
     */
    merge 
        work.patients_sorted (in=p rename=(Status=Base_Status))
        work.encounters_sorted (in=e)
        work.updates_sorted (in=u rename=(Status=New_Status, Amount_Charged=Bill_Amt));

    by Patient_ID;

    /* 
     * LOGIC BLOCK 1: One-to-One / Master Record Initialization
     * If the patient exists in the master file but has no encounters yet,
     * we still need to output the record with default encounter values.
     */
    if p and not e and not u then do;
        Encounter_Count = 0;
        Total_Bill = 0;
        Status_Flag = Base_Status;
        output;
    end;

    /* 
     * LOGIC BLOCK 2: One-to-Many Expansion
     * If we have encounters, we generate a row for each encounter.
     * We aggregate billing data if updates exist for this specific visit window.
     */
    else if p and e then do;
        /* Initialize encounter specific counters */
        if first.Patient_ID then do;
            Encounter_Count = 0;
            Total_Bill = 0;
        end;

        Encounter_Count + 1;

        /* 
         * MERGE_SEMANTICS PATTERN: Conditional UPDATE Logic
         * If a billing update exists for this patient (and by merge logic, 
         * potentially the specific visit context), we update the record.
         * This simulates an 'UPDATE' dataset merging onto a 'Master' dataset.
         */
        if u then do;
            /* 
             * Overwrite specific fields from the update dataset.
             * This is the core of the UPDATE pattern within a MERGE step.
             * We prioritize the 'New_Status' from updates over 'Base_Status'.
             */
            Status_Flag = New_Status;
            if Bill_Amt > 0 then Total_Bill + Bill_Amt;
        end;
        else do;
            /* If no update, retain base status */
            Status_Flag = Base_Status;
        end;

        /* Output the expanded row */
        output;
    end;

    /* 
     * LOGIC BLOCK 3: Orphan Updates (Data Quality Check)
     * If an update exists but no patient record (orphan), log it but do not merge.
     */
    else if u and not p then do;
        put 'WARNING: Orphan billing update found for Patient_ID=' Patient_ID;
        /* Do not output to master, just log */
    end;

    /* 
     * LOGIC BLOCK 4: Final Cleanup for One-to-Many Aggregation
     * If the loop finishes for a Patient_ID and we had encounters, 
     * we might want a summary row or specific logic for the last observation.
     * Here we ensure the last observation carries the aggregated total.
     */
    if last.Patient_ID and p and e then do;
        /* Finalize the status based on the last update processed */
        /* (Logic handled above, this is a placeholder for post-merge checks) */
        if Total_Bill = 0 then Status_Flag = 'No_Charges';
        output;
    end;

    /* 
     * Drop temporary variables used for merge tracking and renaming
     */
    drop Base_Status New_Status Bill_Amt p e u;
run;

/* 
 * Post-Merge Verification
 * Check for any duplicate Patient_IDs if the logic failed, 
 * though the BY-group processing should handle the One-to-Many expansion correctly.
 */
proc freq data=work.patient_master_combined;
    tables Patient_ID / nocum nopercent;
    title 'Frequency Check: Verify One-to-Many Expansion';
run;

/* 
 * Purpose: Calculate running totals and identify lag patterns for sales data.
 * This DATA step demonstrates the use of the RETAIN statement to maintain 
 * values across iterations of the data step, which is essential for 
 * calculating cumulative sums and comparing current rows to previous rows.
 */

data sales_analysis;
    set retail.transactions;

    /* 
     * RETAIN Statement:
     * By default, SAS sets all variables to missing at the start of each iteration.
     * We use RETAIN to preserve the values of 'cumulative_sales' and 'prev_region' 
     * so they carry over from the previous observation to the current one.
     */
    retain cumulative_sales 0 prev_region '';

    /* 
     * Reset cumulative total when the region changes.
     * This logic relies on the 'prev_region' variable retained from the previous row.
     */
    if region ne prev_region then do;
        cumulative_sales = 0;
    end;

    /* Update the retained cumulative total with the current transaction amount */
    cumulative_sales = cumulative_sales + transaction_amount;

    /* 
     * Lag Pattern Implementation:
     * We manually create a 'lagged_amount' by capturing the current amount 
     * into a retained variable at the end of the loop, effectively acting 
     * as a lag function for the next iteration.
     */
    lagged_amount = prev_amount;

    /* Store current values into retained variables for the next iteration */
    prev_region = region;
    prev_amount = transaction_amount;

    /* Calculate difference between current and previous transaction */
    if not missing(lagged_amount) then 
        amount_diff = transaction_amount - lagged_amount;
    else 
        amount_diff = .;

    /* Output the dataset with new calculated variables */
    run;

/* 
 * SAS Code: Customer Running Totals and Lag Analysis
 * Category: DATA_STEP_RETAIN
 * Complexity: MODERATE
 * Description: Calculates cumulative transaction amounts and compares 
 *              current transaction to the previous one using RETAIN and LAG.
 */

data sales_analysis;
    /* Read from a realistic transactional dataset */
    set retail.transactions (keep=customer_id transaction_date amount);

    /* Initialize retained variables for the first record of each customer */
    if first.customer_id then do;
        running_total = 0;
        prev_transaction_date = .;
        prev_amount = .;
        days_since_last = .;
    end;

    /* 
     * Update running total using RETAIN pattern.
     * The RETAIN statement ensures these variables hold their values 
     * across iterations of the DATA step for the same customer.
     */
    retain running_total prev_transaction_date prev_amount;

    /* Calculate the running total for the current customer */
    running_total = sum(running_total, amount);

    /* 
     * Calculate lagged values to analyze trends.
     * LAG function retrieves the value from the previous observation.
     * Note: LAG queue is only populated when the function is executed.
     */
    prev_amount = lag(amount);
    prev_transaction_date = lag(transaction_date);

    /* Calculate days between current and previous transaction */
    if not missing(prev_transaction_date) then do;
        days_since_last = transaction_date - prev_transaction_date;
    end;

    /* 
     * Flag potential anomalies: 
     * If the current transaction is significantly higher than the previous one
     * and it's been more than 30 days since the last purchase.
     */
    if amount > (prev_amount * 1.5) and days_since_last > 30 then 
        anomaly_flag = 'High Value Delayed Purchase';
    else 
        anomaly_flag = 'Normal';

    /* Format output variables for readability */
    format transaction_date date9. amount dollar12.2 running_total dollar12.2;

    /* Keep only relevant variables for the output dataset */
    keep customer_id transaction_date amount running_total 
         prev_amount days_since_last anomaly_flag;
run;

/* Optional: Print a sample of the results to verify calculations */
proc print data=sales_analysis (obs=20) noobs;
    title 'Sample of Customer Running Totals and Lag Analysis';
run;

%macro generate_clinical_report(dataset=, output_lib=, start_date=, end_date=, treatment_group=ALL);
    /*
       Purpose: Generates a summary report for clinical trial data based on specified parameters.
       This macro filters patient records, calculates summary statistics, and outputs a dataset.
    */

    /* Validate input parameters */
    %if &treatment_group = ALL %then %do;
        %let filter_clause = 1;
    %end;
    %else %do;
        %let filter_clause = arm_cd = "&treatment_group";
    %end;

    /* Create the filtered work dataset */
    data work.clinical_filtered;
        set &dataset;
        where visit_dt >= "&start_date"d 
            and visit_dt <= "&end_date"d 
            and &filter_clause;
    run;

    /* Calculate summary statistics by arm */
    proc sql;
        create table &output_lib..summary_stats as
        select 
            arm_cd,
            count(*) as n_patients,
            mean(age) as mean_age format=8.2,
            std(age) as std_age format=8.2,
            mean(systolic_bp) as mean_sbp format=8.1,
            mean(diastolic_bp) as mean_dbp format=8.1
        from work.clinical_filtered
        group by arm_cd;
    quit;

    /* Output a log message confirming completion */
    %put NOTE: Report generation complete for dataset &dataset. Output saved to &output_lib..summary_stats;

%mend generate_clinical_report;

/* Example invocation of the macro */
%generate_clinical_report(
    dataset=work.clinical_trial_v2,
    output_lib=reports,
    start_date=01JAN2023,
    end_date=31DEC2023,
    treatment_group=ARM_A
);
